const j = $input.first().json;
// PoYo Hailuo 2.3 — https://docs.poyo.ai (POST /api/generate/submit)
// poyo_stitch_segments 2+ = несколько задач + склейка; 1 = один клип.
const model = String(j.video_model || 'hailuo-2.3').trim() || 'hailuo-2.3';
let resolution = String(j.hailuo_resolution || '768p').trim().toLowerCase();
if (!['768p', '1080p'].includes(resolution)) resolution = '768p';

let duration = parseInt(String(j.hailuo_duration || '10'), 10);
if (![6, 10].includes(duration)) duration = duration <= 8 ? 6 : 10;
if (resolution === '1080p' && duration === 10) duration = 6;

const userPrompt = String(j.prompt_visual || '').trim();
const styleFix = [
  'vertical 9:16 portrait video for YouTube Shorts and TikTok',
  'full-frame tall narrow composition, phone held upright, portrait orientation',
  'NOT landscape, NOT 16:9 widescreen, NOT horizontal framing',
  'lo-fi hip hop music video, chillhop, soft neon palette, cozy mood',
  'gentle camera motion suited to vertical frame, subtle 35mm grain',
  'no readable text, no logos, no watermark, no faces as main subject',
].join(', ');
const prompt = [userPrompt, styleFix].filter(Boolean).join(', ');

const tags = String(j.tags || '')
  .split(',')
  .map((t) => t.trim())
  .filter(Boolean);

const shortsCount = Math.max(1, parseInt(String(j.shorts_count || '1'), 10) || 1);
const clipSeconds = Math.max(5, parseInt(String(j.clip_seconds || '30'), 10) || 30);
const poyoStitchSegments = Math.min(4, Math.max(1, parseInt(String(j.poyo_stitch_segments || '1'), 10) || 1));

const rawName = String(j.output_filename || '').trim();
const outputFilename = rawName || `poyo-hailuo-lofi-${Date.now()}.mp4`;

const trackMeta = String(j.track_for_metadata || '').trim() || null;
const theme = String(j.theme || 'Lo-fi Hip Hop').trim();
const privacy = String(j.shorts_privacy_status || 'public').trim() || 'public';

const aspect = String(j.hailuo_aspect_ratio || '9:16').trim() || '9:16';
const input = {
  prompt,
  duration,
  resolution,
  aspect_ratio: aspect,
  prompt_optimizer: j.hailuo_prompt_optimizer !== false && j.hailuo_prompt_optimizer !== 'false',
};
const startUrl = String(j.hailuo_start_image_url || '').trim();
if (startUrl) input.start_image_url = startUrl;

return [{
  json: {
    poyo_payload: { model, input },
    output_filename: outputFilename,
    track_for_metadata: trackMeta,
    theme,
    tags,
    publish_at_iso: new Date().toISOString(),
    shorts_count: shortsCount,
    short_delay_hours: 0,
    short_interval_hours: 24,
    clip_seconds: clipSeconds,
    shorts_privacy_status: privacy,
    cleanup_source_after_publish: true,
    cleanup_shorts_after_upload: true,
    poyo_stitch_segments: poyoStitchSegments,
  },
}];
